<template><div class="auth-page"><el-card class="auth-box"><h2>注册账号</h2><el-form :model="form"><el-form-item><el-input v-model="form.username" placeholder="用户名"/></el-form-item><el-form-item><el-input v-model="form.email" placeholder="邮箱"/></el-form-item><el-form-item><el-input v-model="form.password" type="password" show-password placeholder="密码"/></el-form-item><el-form-item><el-input v-model="confirm" type="password" show-password placeholder="确认密码"/></el-form-item><el-button class="full" type="primary" :loading="loading" @click="submit">注册</el-button><p class="muted">已有账号？<router-link to="/login">去登录</router-link></p></el-form></el-card></div></template>
<script setup>import { reactive,ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import { useUserStore } from '../stores/user';const router=useRouter(),store=useUserStore(),loading=ref(false),confirm=ref('');const form=reactive({username:'',email:'',password:''});async function submit(){if(!form.username||!form.password)return ElMessage.warning('请填写用户名和密码');if(form.password!==confirm.value)return ElMessage.warning('两次密码不一致');loading.value=true;try{await store.doRegister(form);ElMessage.success('注册成功，请登录');router.push('/login')}finally{loading.value=false}}</script>
